  describe('state invariants (stateful PBT)', () => {
    it('always: chord is non-empty', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('register'), input: fc.record({ binding: fc.string(), label: fc.string({ minLength: 1, maxLength: 50 }), description: fc.string(), category: fc.string({ minLength: 1, maxLength: 50 }), scope: fc.string({ minLength: 1, maxLength: 50 }), priority: fc.integer({ min: 1, max: 1000 }), chord: fc.string(), phase: fc.string({ minLength: 1, maxLength: 50 }), onlyOutsideTextInput: fc.boolean(), overridesBrowser: fc.boolean(), actionBinding: fc.string(), params: fc.string() }) }),
              fc.record({ action: fc.constant('deregister'), input: fc.record({ binding: fc.string() }) }),
              fc.record({ action: fc.constant('resolveKey'), input: fc.record({ scope: fc.string({ minLength: 1, maxLength: 50 }), eventKey: fc.string({ minLength: 1, maxLength: 50 }), eventCode: fc.string({ minLength: 1, maxLength: 50 }), modifiers: fc.string(), chordState: fc.string() }) }),
              fc.record({ action: fc.constant('listByScope'), input: fc.record({ scope: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('listByCategory'), input: fc.record({ category: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('setOverride'), input: fc.record({ binding: fc.string(), scope: fc.string({ minLength: 1, maxLength: 50 }), chord: fc.string() }) }),
              fc.record({ action: fc.constant('clearOverride'), input: fc.record({ binding: fc.string(), scope: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = keyBindingHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(keyBindingHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: two bindings same scope chord priority', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('register'), input: fc.record({ binding: fc.string(), label: fc.string({ minLength: 1, maxLength: 50 }), description: fc.string(), category: fc.string({ minLength: 1, maxLength: 50 }), scope: fc.string({ minLength: 1, maxLength: 50 }), priority: fc.integer({ min: 1, max: 1000 }), chord: fc.string(), phase: fc.string({ minLength: 1, maxLength: 50 }), onlyOutsideTextInput: fc.boolean(), overridesBrowser: fc.boolean(), actionBinding: fc.string(), params: fc.string() }) }),
              fc.record({ action: fc.constant('deregister'), input: fc.record({ binding: fc.string() }) }),
              fc.record({ action: fc.constant('resolveKey'), input: fc.record({ scope: fc.string({ minLength: 1, maxLength: 50 }), eventKey: fc.string({ minLength: 1, maxLength: 50 }), eventCode: fc.string({ minLength: 1, maxLength: 50 }), modifiers: fc.string(), chordState: fc.string() }) }),
              fc.record({ action: fc.constant('listByScope'), input: fc.record({ scope: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('listByCategory'), input: fc.record({ category: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('setOverride'), input: fc.record({ binding: fc.string(), scope: fc.string({ minLength: 1, maxLength: 50 }), chord: fc.string() }) }),
              fc.record({ action: fc.constant('clearOverride'), input: fc.record({ binding: fc.string(), scope: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = keyBindingHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(keyBindingHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: two bindings same scope chord priority
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

